-- Chien -> humain, Fête, Volume 8

insert into public.message_templates (user_id,title,content,tone,is_system,is_manual_only,occasion,animal_type,animal_direction) values

(null,'Joyeuse fête. J''ai observé ta façon de sourire quand quelqu''un dit quelque chose de gentil sur toi en public.',$$Joyeuse fête. J''ai observé ta façon de sourire quand quelqu''un dit quelque chose de gentil sur toi en public.
Une légère hésitation. Puis tu remercies simplement. Sans minimiser. Sans surjouer. Tu accueilles le compliment public avec la même grâce que le compliment privé. Joyeuse fête, mon humain préféré.
Avec observation de ton accueil parfaitement dosé du compliment public, — {prenom}, ton animal expert en réception gracieuse 🌷$$,'humorous',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. J''ai observé comment tu fais semblant d''aimer quelque chose que tu n''aimes pas vraiment.',$$Joyeuse fête. J''ai observé comment tu fais semblant d''aimer quelque chose que tu n''aimes pas vraiment.
Une fois ce soir. Quelqu''un t''a donné quelque chose qui n''était pas tout à fait ton goût. Et tu as trouvé l''angle positif. La chose vraie dans ce que tu pouvais dire de bien. Joyeuse fête, mon humain préféré.
Avec observation de ton art de trouver le vrai positif dans tout, — {prenom}, ton animal admirateur de ta diplomatie sincère 🎨$$,'humorous',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. Je comprends pas pourquoi les gens se lèvent en même temps pour débarrasser.',$$Joyeuse fête. Je comprends pas pourquoi les gens se lèvent en même temps pour débarrasser.
Le repas finit. Et comme par signal invisible plusieurs personnes se lèvent et commencent à débarrasser. Ce geste collectif spontané. Il y a quelque chose de beau dans cette synchronisation involontaire. Joyeuse fête, mon humain préféré.
Avec reconnaissance de la beauté de la synchronisation involontaire du débarrassage, — {prenom}, ton animal qui aurait aussi aidé si j''avais des mains 🍽️$$,'humorous',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. J''ai étudié ta façon de reprendre de l''énergie entre deux conversations.',$$Joyeuse fête. J''ai étudié ta façon de reprendre de l''énergie entre deux conversations.
Une gorgée. Un regard vers la pièce. Une respiration un peu plus profonde. Ces micro-pauses de recharge. Ces moments de ravitaillement invisible avant de replonger. Cette économie de l''énergie sociale que tu gères sans y penser. Joyeuse fête, mon humain préféré.
Avec observation de tes micro-pauses de recharge et leur efficacité invisible, — {prenom}, ton animal expert en gestion de l''énergie sociale 🔋$$,'humorous',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. J''ai observé ta façon de t''assurer que personne ne part sans au revoir.',$$Joyeuse fête. J''ai observé ta façon de t''assurer que personne ne part sans au revoir.
Tu surveilles les départs. Pas ostensiblement. Mais tu remarques quand quelqu''un commence à rassembler ses affaires. Et tu vas vers lui avant qu''il parte. Pour que personne ne disparaisse sans que tu l''aies vu partir. Joyeuse fête, mon humain préféré.
Avec observation de ta surveillance des départs et ton soin à clore chaque relation proprement, — {prenom}, ton animal expert en clôtures relationnelles 🚪$$,'touching',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. J''ai observé comment tu réagis quand quelqu''un dit quelque chose d''inexact sur toi.',$$Joyeuse fête. J''ai observé comment tu réagis quand quelqu''un dit quelque chose d''inexact sur toi.
Tu souris. Tu laisses passer si ce n''est pas important. Si c''est important tu corriges doucement. Avec humour parfois. Sans que l''autre se sente attaqué. Joyeuse fête, mon humain préféré.
Avec admiration pour ta défense douce de la vérité sur toi-même, — {prenom}, ton animal témoin de ton assertivité gracieuse 🌿$$,'touching',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. Je comprends pas pourquoi les gens disent qu''ils sont nuls en cuisine avant de manger.',$$Joyeuse fête. Je comprends pas pourquoi les gens disent qu''ils sont nuls en cuisine avant de manger.
Ce soir quelqu''un a dit ça. Je suis vraiment nul en cuisine. Et puis tout le monde a mangé. Et la cuisine en question était plutôt bonne. Peut-être que minimiser avant c''est une façon de gérer les attentes. Je comprends la stratégie. Joyeuse fête, mon humain préféré.
Avec compréhension de la modestie préventive et de sa logique de gestion des attentes, — {prenom}, ton animal stratège des premières impressions 🍳$$,'humorous',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. J''ai mémorisé chaque fois que tu as penché la tête pour mieux écouter.',$$Joyeuse fête. J''ai mémorisé chaque fois que tu as penché la tête pour mieux écouter.
Ce geste. Cette légère inclinaison de la tête quand quelqu''un dit quelque chose qui mérite plus d''attention. Ton oreille qui se rapproche. Tes yeux qui se concentrent. Ce soir j''ai compté cinq fois. Joyeuse fête, mon humain préféré.
Avec cinq inclinations de tête mémorisées et leur signification d''écoute vraie, — {prenom}, ton animal admirateur de tes signaux d''attention 👂$$,'humorous',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. J''ai observé ta façon de ranger les chaises après la fête.',$$Joyeuse fête. J''ai observé ta façon de ranger les chaises après la fête.
Proprement. À leur place habituelle. Avec ce geste de remise en ordre. Pas avec regret. Avec une certaine satisfaction. Joyeuse fête, mon humain préféré.
Avec observation de ton rangement de chaises et sa satisfaction de l''ordre retrouvé, — {prenom}, ton animal témoin de tes rituels de remise en ordre 🪑$$,'humorous',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. J''ai observé comment tu traites quelqu''un qui dit quelque chose de maladroit.',$$Joyeuse fête. J''ai observé comment tu traites quelqu''un qui dit quelque chose de maladroit.
Tu ne le laisses pas dans l''embarras. Tu relances sur autre chose. Tu fais une transition qui dit que ce qui vient d''être dit n''était pas grave. Cette façon de protéger les autres de leurs propres faux pas. Joyeuse fête, mon humain préféré.
Avec admiration pour ta protection des autres de leurs propres faux pas, — {prenom}, ton animal expert en sauvetages sociaux invisibles 🎭$$,'humorous',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. Je comprends pas pourquoi les gens gardent leurs téléphones face vers le bas mais les retournent quand même.',$$Joyeuse fête. Je comprends pas pourquoi les gens gardent leurs téléphones face vers le bas mais les retournent quand même.
Ce soir plusieurs téléphones étaient posés face vers le bas. Signalant une intention de présence. Mais à plusieurs reprises les mêmes téléphones ont été retournés. Cette lutte entre l''intention et le réflexe. Joyeuse fête, mon humain préféré.
Avec fascination pour la lutte entre l''intention de présence et le réflexe numérique, — {prenom}, ton animal exempt de ce conflit spécifique 📱$$,'humorous',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. J''ai étudié ta façon de fermer les fenêtres quand les invités partent.',$$Joyeuse fête. J''ai étudié ta façon de fermer les fenêtres quand les invités partent.
Une par une. Doucement. Comme si fermer les fenêtres c''était aussi fermer la soirée progressivement. Comme si l''appartement devait retrouver son air à lui. Sa chaleur à lui. Joyeuse fête, mon humain préféré.
Avec interprétation poétique de tes fenêtres fermées comme clôture progressive de la soirée, — {prenom}, ton animal poète de tes gestes de fin 🪟$$,'humorous',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. J''ai observé comment ton visage change quand tu es fatigué mais que tu continues.',$$Joyeuse fête. J''ai observé comment ton visage change quand tu es fatigué mais que tu continues.
Il y a eu un moment. Tard dans la soirée. Où j''ai vu la fatigue passer sur ton visage une seconde. Puis tu t''es repris. Un sourire. Un effort. Une reprise. Joyeuse fête, mon humain préféré.
Avec observation de ta reprise tardive et admiration pour tes réserves cachées, — {prenom}, ton animal témoin de ton endurance gracieuse 💪$$,'humorous',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. J''ai observé comment tu réagis quand quelqu''un refuse un dessert.',$$Joyeuse fête. J''ai observé comment tu réagis quand quelqu''un refuse un dessert.
Tu proposes. Il dit non merci. Et tu passes à autre chose. Sans insister. Sans faire de la chose un sujet. Sans que le refus devienne une déception visible. Joyeuse fête, mon humain préféré.
Avec admiration pour ton acceptation du non sans déception visible, — {prenom}, ton animal admirateur de ta grâce dans le refus reçu 🍮$$,'humorous',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. Je comprends pas pourquoi les gens disent un peu et prennent beaucoup.',$$Joyeuse fête. Je comprends pas pourquoi les gens disent un peu et prennent beaucoup.
Ce soir plusieurs personnes ont dit un peu seulement avant qu''on leur serve quelque chose. Et ont pris des portions généreuses. Peut-être que un peu c''est relatif à ce qu''on aurait voulu. Moi aussi mes portions sont relatives. Joyeuse fête, mon humain préféré.
Avec compréhension de la relativité du peu et solidarité de mes propres portions généreuses, — {prenom}, ton animal aux évaluations quantitatives également relatives 🍽️$$,'humorous',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. J''ai mémorisé ton regard quand tout allait vraiment bien en même temps.',$$Joyeuse fête. J''ai mémorisé ton regard quand tout allait vraiment bien en même temps.
Il y a eu un moment. Vers 21h. Où tout allait bien en même temps. Et toi tu as regardé la pièce. Un tour complet. Lent. Et tu souriais. Ce sourire qui dit que c''est exactement ça qu''on voulait. Joyeuse fête, mon humain préféré.
Avec mémorisation de ton regard panoramique à 21h et son sourire de satisfaction totale, — {prenom}, ton animal gardien de tes moments de plénitude 🌟$$,'humorous',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. J''ai observé ta façon d''ouvrir la fenêtre après la fête pour aérer.',$$Joyeuse fête. J''ai observé ta façon d''ouvrir la fenêtre après la fête pour aérer.
Grande ouverte. Pour quelques minutes. Laisser entrer l''air frais. Laisser sortir les odeurs de la soirée. Cette façon de purifier l''espace. De marquer la transition entre la fête et le silence qui suit. Joyeuse fête, mon humain préféré.
Avec observation de ton aération post-fête comme rituel de transition vers le silence, — {prenom}, ton animal expert en transitions atmosphériques 🌬️$$,'humorous',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. J''ai observé comment tu gères le silence collectif.',$$Joyeuse fête. J''ai observé comment tu gères le silence collectif.
Tu ne le remplis pas tout de suite. Tu le laisses exister un moment. Tu regardes autour. Tu prends une gorgée. Et si le silence dure tu dis quelque chose de léger qui relance. Cette gestion des silences. Joyeuse fête, mon humain préféré.
Avec observation de ta gestion des silences collectifs et leur espace accordé, — {prenom}, ton animal appréciant les respirations dans le bruit collectif 🌬️$$,'humorous',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. Je comprends pas pourquoi les gens apportent des choses en double.',$$Joyeuse fête. Je comprends pas pourquoi les gens apportent des choses en double.
Ce soir deux personnes ont apporté du même type de chose. Sans se concerter. Peut-être que les doublons c''est une preuve de complicité. Que vos esprits fonctionnent pareil. Dans ce cas c''est un beau signe. Joyeuse fête, mon humain préféré.
Avec interprétation positive du doublon comme preuve de complicité des esprits, — {prenom}, ton animal optimiste des coïncidences 🎁$$,'humorous',true,false,'nameday','chien','from'),

(null,'Joyeuse fête. J''ai étudié ta façon de te reposer dans ta propre fête.',$$Joyeuse fête. J''ai étudié ta façon de te reposer dans ta propre fête.
Tu as trouvé des moments. Courts. Assis quelque part. Une gorgée. Un regard vers rien. Quelques secondes de non-animation. Ces mini-pauses dans le flux de la soirée. Ces moments où tu existais pour toi seul au milieu de tout le monde. Joyeuse fête, mon humain préféré.
Avec observation de tes mini-pauses de recharge au milieu de tout le monde, — {prenom}, ton animal témoin de tes moments pour toi dans le collectif 🌿$$,'touching',true,false,'nameday','chien','from')

on conflict do nothing;
